const checkpoints = [];

function dateOnly(iso) { return String(iso).slice(0, 10); }
function calcDistanceMiles(lat1, lon1, lat2, lon2) {
  if (lat1 == null || lon1 == null || lat2 == null || lon2 == null) return null;
  const toRad = deg => (deg * Math.PI) / 180;
  const R = 3958.8;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
            Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

const activities = JSON.parse(localStorage.getItem('activities') || '[]');
const sessions = JSON.parse(localStorage.getItem('activity_sessions') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const favoritesLists = JSON.parse(localStorage.getItem('favorites_lists') || '[]');
const favoriteItems = JSON.parse(localStorage.getItem('favorite_items') || '[]');
let userDefaultLoc = null;
try { userDefaultLoc = JSON.parse(localStorage.getItem('user_default_location') || 'null'); } catch (e) {}

const today = new Date();
const day = today.getDay(); // 0=Sun
const daysUntilSaturday = (6 - day + 7) % 7 || 7; // upcoming Saturday (not today)
const upcomingSaturday = new Date(today);
upcomingSaturday.setDate(today.getDate() + daysUntilSaturday);
const upcomingSaturdayStr = dateOnly(upcomingSaturday.toISOString());

const activitiesById = {};
activities.forEach(a => { activitiesById[a.id] = a; });
const sessionsByActivity = {};
sessions.forEach(s => {
  if (!sessionsByActivity[s.activity_id]) sessionsByActivity[s.activity_id] = [];
  sessionsByActivity[s.activity_id].push(s);
});
const locationsById = {};
locations.forEach(l => { locationsById[l.id] = l; });

const defaultLat = userDefaultLoc && typeof userDefaultLoc.latitude === 'number' ? userDefaultLoc.latitude : null;
const defaultLon = userDefaultLoc && typeof userDefaultLoc.longitude === 'number' ? userDefaultLoc.longitude : null;

// Find qualifying activities and their earliest Saturday session
const qualifyingEntries = [];
for (const activity of activities) {
  if (activity.content_group !== 'events') continue;
  if (activity.activity_category !== 'outdoor') continue;
  const actMinAge = typeof activity.min_age === 'number' ? activity.min_age : 0;
  const actMaxAge = typeof activity.max_age === 'number' ? activity.max_age : Infinity;
  if (actMaxAge < 5 || actMinAge > 8) continue;
  if (activity.price_type !== 'free') continue;

  const actSessions = sessionsByActivity[activity.id] || [];
  let bestSession = null;
  for (const s of actSessions) {
    if (dateOnly(s.start_datetime) !== upcomingSaturdayStr) continue;
    if (!bestSession || new Date(s.start_datetime) < new Date(bestSession.start_datetime)) {
      bestSession = s;
    }
  }
  if (!bestSession) continue;

  const loc = locationsById[activity.location_id] || null;
  let distance = null;
  if (loc && defaultLat != null && defaultLon != null) {
    distance = calcDistanceMiles(defaultLat, defaultLon, loc.latitude, loc.longitude);
    if (typeof distance === 'number' && distance > 10) continue; // enforce 10-mile radius only if we can compute
  }

  qualifyingEntries.push({ activity, bestSession, distance });
}

// Sort by earliest start time
qualifyingEntries.sort((a, b) => new Date(a.bestSession.start_datetime) - new Date(b.bestSession.start_datetime));

const allQualifyingActivityIds = qualifyingEntries.map(e => e.activity.id);
const top2 = qualifyingEntries.slice(0, 2);
const top2ActivityIds = top2.map(e => e.activity.id);

// Get favorited activity ids
let favoritesList = null;
if (favoritesLists.length) {
  favoritesList = favoritesLists.find(l => l.name === 'Favorites') || favoritesLists[0];
}
let favoritedActivityIds = [];
if (favoritesList) {
  favoritedActivityIds = favoriteItems
    .filter(fi => fi.favorites_list_id === favoritesList.id)
    .map(fi => fi.activity_id);
}

const favoritedQualifyingIds = favoritedActivityIds.filter(id => allQualifyingActivityIds.includes(id));
const top2FavoritedCount = top2ActivityIds.filter(id => favoritedActivityIds.includes(id)).length;

// CP1 (0.30): At least one qualifying upcoming-Saturday free outdoor 5–8 event was favorited
checkpoints.push({ passed: favoritedQualifyingIds.length >= 1, weight: 0.30 });

// CP2 (0.30): At least two qualifying events were favorited
checkpoints.push({ passed: favoritedQualifyingIds.length >= Math.min(2, allQualifyingActivityIds.length), weight: 0.30 });

// CP3 (0.40): The first two (earliest) qualifying events were both favorited
checkpoints.push({ passed: top2ActivityIds.length >= 2 && top2FavoritedCount === top2ActivityIds.length, weight: 0.40 });

const score = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
return score;

