const activities = JSON.parse(localStorage.getItem('activities') || '[]');
const sessions = JSON.parse(localStorage.getItem('activity_sessions') || '[]');
const dayPlans = JSON.parse(localStorage.getItem('day_plans') || '[]');
const dayPlanItems = JSON.parse(localStorage.getItem('day_plan_items') || '[]');

const sessionsById = {};
sessions.forEach(s => { sessionsById[s.id] = s; });
const activitiesById = {};
activities.forEach(a => { activitiesById[a.id] = a; });

// Compute upcoming Sunday as BusinessLogic.getDateShortcuts does
const today = new Date();
const day = today.getDay(); // 0=Sun
const daysUntilSunday = (7 - day + 7) % 7 || 7; // upcoming Sunday (not today)
const upcomingSunday = new Date(today);
upcomingSunday.setDate(today.getDate() + daysUntilSunday);
const upcomingSundayStr = dateOnly(upcomingSunday.toISOString());

const plan = dayPlans.find(p => dateOnly(p.date) === upcomingSundayStr) || null;
let itemsForDay = [];
if (plan) {
  itemsForDay = dayPlanItems.filter(i => i.day_plan_id === plan.id);
}

function getTimeBucket(item, session) {
  return item.time_of_day_bucket || (session ? session.time_of_day_bucket : null);
}

function getEffectiveMaxPrice(activity) {
  if (!activity) return Infinity;
  if (activity.price_type === 'free') return 0;
  const max = typeof activity.price_max === 'number' ? activity.price_max : null;
  const min = typeof activity.price_min === 'number' ? activity.price_min : null;
  if (max != null) return max;
  if (min != null) return min;
  return Infinity;
}

let hasMorningIndoorUnder20 = false;
let hasAfternoonParksPlaygrounds = false;
let hasEveningShowUnder50 = false;

for (const item of itemsForDay) {
  const activity = activitiesById[item.activity_id];
  if (!activity) continue;
  const session = item.session_id ? sessionsById[item.session_id] : null;
  if (!session || dateOnly(session.start_datetime) !== upcomingSundayStr) continue;

  const bucket = getTimeBucket(item, session);
  const maxPrice = getEffectiveMaxPrice(activity);

  if (bucket === 'morning' && activity.activity_category === 'indoor' && maxPrice <= 20) {
    hasMorningIndoorUnder20 = true;
  }
  if (bucket === 'afternoon' && activity.activity_category === 'parks_playgrounds') {
    hasAfternoonParksPlaygrounds = true;
  }
  if (bucket === 'evening' && activity.activity_category === 'shows_performances' && maxPrice <= 50) {
    hasEveningShowUnder50 = true;
  }
}

// CP1 (0.34): Day plan includes an indoor morning event on Sunday with effective price <= $20
checkpoints.push({ passed: hasMorningIndoorUnder20, weight: 0.34 });

// CP2 (0.33): Day plan includes an afternoon parks/playgrounds event on Sunday
checkpoints.push({ passed: hasAfternoonParksPlaygrounds, weight: 0.33 });

// CP3 (0.33): Day plan includes an evening show/performance on Sunday with effective price <= $50
checkpoints.push({ passed: hasEveningShowUnder50, weight: 0.33 });

const score = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
return score;

