const sessionsById = {};
sessions.forEach(s => { sessionsById[s.id] = s; });

// Compute next month date range as BusinessLogic.getDateShortcuts does
const today = new Date();
const year = today.getFullYear();
const month = today.getMonth();
const nextMonthStart = new Date(year, month + 1, 1);
const nextMonthEnd = new Date(year, month + 2, 0);
const nextMonthStartStr = dateOnly(nextMonthStart.toISOString());
const nextMonthEndStr = dateOnly(nextMonthEnd.toISOString());

// Find qualifying workshops and their Saturday-morning sessions next month
const qualifyingWorkshops = [];
for (const activity of activities) {
  if (activity.content_group !== 'workshops_camps') continue;
  const actMinAge = typeof activity.min_age === 'number' ? activity.min_age : 0;
  const actMaxAge = typeof activity.max_age === 'number' ? activity.max_age : Infinity;
  if (actMaxAge < 10 || actMinAge > 12) continue;

  const actSessions = sessions.filter(s => s.activity_id === activity.id);
  let bestSession = null;
  for (const s of actSessions) {
    const dStr = dateOnly(s.start_datetime);
    if (dStr < nextMonthStartStr || dStr > nextMonthEndStr) continue;
    if (s.day_of_week !== 'saturday') continue;
    if (s.time_of_day_bucket !== 'morning') continue;
    if (!bestSession || new Date(s.start_datetime) < new Date(bestSession.start_datetime)) {
      bestSession = s;
    }
  }
  if (!bestSession) continue;

  const priceMin = typeof activity.price_min === 'number' ? activity.price_min : Infinity;
  const priceMax = typeof activity.price_max === 'number' ? activity.price_max : priceMin;
  const perTicketCap = priceMax; // enforce max ticket price <= 40
  if (perTicketCap > 40) continue;

  const sortPrice = priceMin === Infinity ? priceMax : priceMin;
  qualifyingWorkshops.push({ activity, bestSession, sortPrice });
}

qualifyingWorkshops.sort((a, b) => a.sortPrice - b.sortPrice);

const cheapestWorkshop = qualifyingWorkshops[0] || null;
const cheapestActivityId = cheapestWorkshop ? cheapestWorkshop.activity.id : null;

// Consider only registrations created after the baseline date to avoid counting seeded data
let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let newRegistrations = registrations;
if (baselineDateStr) {
  const baselineDate = new Date(baselineDateStr + 'T00:00:00Z');
  newRegistrations = registrations.filter(r => new Date(r.created_at) > baselineDate);
}

// Registrations for qualifying workshops next month, Saturday morning
const regsForQualifying = newRegistrations.filter(r => {
  const act = activitiesById[r.activity_id];
  const ses = sessionsById[r.session_id];
  if (!act || !ses) return false;
  const match = qualifyingWorkshops.find(q => q.activity.id === act.id && q.bestSession.id === ses.id);
  if (!match) return false;
  const perTicket = r.participants_count ? ((r.total_price || 0) / r.participants_count) : 0;
  if (perTicket > 40) return false;
  return true;
});

// Fully qualified registrations: correct workshop, 2 participants, contact details
const fullyQualifiedRegs = regsForQualifying.filter(r => {
  if (r.participants_count !== 2) return false;
  if (!r.parent_guardian_name || String(r.parent_guardian_name).trim().length === 0) return false;
  if (!r.contact_phone || String(r.contact_phone).trim().length === 0) return false;
  return true;
});

const cheapestQualifiedReg = fullyQualifiedRegs.find(r => r.activity_id === cheapestActivityId) || null;

// CP1 (0.30): At least one registration was created for a qualifying next-month Saturday morning workshop with per-ticket price <= $40
checkpoints.push({ passed: regsForQualifying.length > 0, weight: 0.30 });

// CP2 (0.30): At least one such registration used exactly 2 participants and included required contact details
checkpoints.push({ passed: fullyQualifiedRegs.length > 0, weight: 0.30 });

// CP3 (0.40): The fully qualified registration is for the cheapest qualifying workshop
checkpoints.push({ passed: !!cheapestWorkshop && !!cheapestQualifiedReg, weight: 0.40 });

const score = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
return score;

