let maxIncluded = 0;
for (const m of familyUnder150) {
  const num = typeof m.included_free_events_per_year === 'number' ? m.included_free_events_per_year : 0;
  if (num > maxIncluded) maxIncluded = num;
}
const bestMembershipIds = familyUnder150.filter(m => (m.included_free_events_per_year || 0) === maxIncluded).map(m => m.id);

// Cart items for family memberships under $150 with annual billing
const cartFamilyAnnual = cartItems.filter(ci => {
  const m = membershipById[ci.membership_id];
  if (!m) return false;
  return m.membership_type === 'family' && typeof m.price === 'number' && m.price <= 150 && ci.billing_period === 'annual' && (ci.quantity || 0) > 0;
});

const cartBestFamilyAnnual = cartFamilyAnnual.filter(ci => bestMembershipIds.includes(ci.membership_id));

// CP1 (0.40): User added some family membership under $150 with annual billing to the cart
