// CP2 (0.60): At least one such cart item is for the membership with the highest included free events per year
checkpoints.push({ passed: cartBestFamilyAnnual.length > 0, weight: 0.60 });

const score = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
return score;

