const sessions = JSON.parse(localStorage.getItem('activity_sessions') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const watchlists = JSON.parse(localStorage.getItem('watchlists') || '[]');
const watchlistItems = JSON.parse(localStorage.getItem('watchlist_items') || '[]');
let userDefaultLoc = null;
try { userDefaultLoc = JSON.parse(localStorage.getItem('user_default_location') || 'null'); } catch (e) {}

