const dLat = userDefaultLoc && typeof userDefaultLoc.latitude === 'number' ? userDefaultLoc.latitude : null;
const dLon = userDefaultLoc && typeof userDefaultLoc.longitude === 'number' ? userDefaultLoc.longitude : null;
const distancePossible = dLat != null && dLon != null;

// Find qualifying classes
const weekdayNames = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday'];
const candidateEntries = [];
for (const activity of activities) {
  if (activity.content_group !== 'classes_programs') continue;
  if (activity.schedule_recurrence !== 'weekly') continue;
  const actMinAge = typeof activity.min_age === 'number' ? activity.min_age : 0;
  const actMaxAge = typeof activity.max_age === 'number' ? activity.max_age : Infinity;
  if (actMaxAge < 3 || actMinAge > 4) continue;

  const actSessions = sessionsByActivity[activity.id] || [];
  const hasWeekdayAfter4 = actSessions.some(s => weekdayNames.includes(s.day_of_week) && s.time_of_day_bucket === 'after_4pm');
  if (!hasWeekdayAfter4) continue;

  const loc = locationsById[activity.location_id] || null;
  let distance = null;
  if (loc && distancePossible) {
    distance = calcDistanceMiles(dLat, dLon, loc.latitude, loc.longitude);
    if (typeof distance === 'number' && distance > 5) continue; // enforce 5-mile radius when possible
  }

  candidateEntries.push({ activity, distance });
}

candidateEntries.sort((a, b) => {
  const dA = a.distance == null ? Number.POSITIVE_INFINITY : a.distance;
  const dB = b.distance == null ? Number.POSITIVE_INFINITY : b.distance;
  return dA - dB;
});

const candidateActivityIds = candidateEntries.map(e => e.activity.id);
const requiredCount = Math.min(3, candidateActivityIds.length);
const expectedTop3Ids = candidateEntries.slice(0, 3).map(e => e.activity.id);

// Get watchlist and saved activity ids
let watchlist = null;
if (watchlists.length) {
  watchlist = watchlists.find(w => w.name === 'Classes Watchlist') || watchlists[0];
}
let savedActivityIds = [];
if (watchlist) {
  savedActivityIds = watchlistItems
    .filter(wi => wi.watchlist_id === watchlist.id)
    .map(wi => wi.activity_id);
}

const savedQualifyingIds = savedActivityIds.filter(id => candidateActivityIds.includes(id));
const hasAllTop3 = expectedTop3Ids.length >= 3 && expectedTop3Ids.every(id => savedQualifyingIds.includes(id));

// CP1 (0.30): At least one qualifying weekly weekday 3–4yo after-4pm class within 5 miles saved to watchlist
checkpoints.push({ passed: savedQualifyingIds.length >= 1, weight: 0.30 });

// CP2 (0.30): At least the first 3 (or all, if fewer exist) qualifying classes are saved
checkpoints.push({ passed: savedQualifyingIds.length >= requiredCount && requiredCount > 0, weight: 0.30 });

// CP3 (0.40): When distance is known and 3+ candidates exist, the saved set includes the 3 nearest classes; otherwise require 3 qualifying saves
let cp3Passed = false;
if (distancePossible && candidateActivityIds.length >= 3) {
  cp3Passed = hasAllTop3;
} else {
  cp3Passed = savedQualifyingIds.length >= requiredCount && requiredCount > 0;
}
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

const score = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
return score;

