const activities = JSON.parse(localStorage.getItem('activities') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const dayPlanItems = JSON.parse(localStorage.getItem('day_plan_items') || '[]');

const activitiesById = {};
activities.forEach(a => { activitiesById[a.id] = a; });
const locationsById = {};
locations.forEach(l => { locationsById[l.id] = l; });

// Determine map center as Riverside Park neighborhood
let centerLoc = locations.find(l => l.neighborhood === 'Riverside Park') || locations.find(l => l.id === 'riverside_park') || null;
const centerLat = centerLoc && typeof centerLoc.latitude === 'number' ? centerLoc.latitude : null;
const centerLon = centerLoc && typeof centerLoc.longitude === 'number' ? centerLoc.longitude : null;

let hasPlayground = false;
let hasStorytime = false;

for (const item of dayPlanItems) {
  const activity = activitiesById[item.activity_id];
  if (!activity) continue;
  const loc = locationsById[activity.location_id] || null;
  let withinRadius = true;
  if (centerLat != null && centerLon != null && loc) {
    const dist = calcDistanceMiles(centerLat, centerLon, loc.latitude, loc.longitude);
    withinRadius = typeof dist !== 'number' || dist <= 2;
  }
  if (!withinRadius) continue;

  if (activity.activity_category === 'playground') {
    hasPlayground = true;
  }
  if (activity.activity_category === 'storytime') {
    hasStorytime = true;
  }
}

// CP1 (0.50): At least one playground-category activity within 2 miles of Riverside Park is in a day plan
checkpoints.push({ passed: hasPlayground, weight: 0.50 });

// CP2 (0.50): At least one storytime-category activity within 2 miles of Riverside Park is in a day plan
checkpoints.push({ passed: hasStorytime, weight: 0.50 });

const score = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
return score;

