sessions.forEach(s => {
  if (!sessionsByActivity[s.activity_id]) sessionsByActivity[s.activity_id] = [];
  sessionsByActivity[s.activity_id].push(s);
});
const locationsById = {};
locations.forEach(l => { locationsById[l.id] = l; });

const paradeCandidateIds = new Set();
const lightsCandidateIds = new Set();

for (const activity of activities) {
  if (activity.content_group !== 'seasonal_holiday') continue;
  const tags = Array.isArray(activity.tags) ? activity.tags : [];
  if (!tags.includes('holiday')) continue;

  const actSessions = sessionsByActivity[activity.id] || [];
  for (const s of actSessions) {
    if (!inDec20to24(s.start_datetime)) continue;

    if (s.time_of_day_bucket === 'daytime') {
      // Parade: holiday + free_parking tag + free price
      const loc = locationsById[activity.location_id] || null;
      const hasFreeParkingTag = tags.includes('free_parking');
      const locationHasFreeParking = loc && loc.has_free_parking === true;
      if (activity.price_type === 'free' && hasFreeParkingTag && locationHasFreeParking) {
        paradeCandidateIds.add(activity.id);
      }
    }

    if (s.time_of_day_bucket === 'evening') {
      // Lights display: holiday tag, tickets under $25
      const priceMax = typeof activity.price_max === 'number' ? activity.price_max : (typeof activity.price_min === 'number' ? activity.price_min : Infinity);
      if (priceMax <= 25) {
        lightsCandidateIds.add(activity.id);
      }
    }
  }
}

