checkpoints.push({ passed: paradeFavorited, weight: 0.50 });

// CP2 (0.50): User favorited at least one qualifying evening holiday lights display with tickets under $25 between Dec 20–24
checkpoints.push({ passed: lightsFavorited, weight: 0.50 });

const score = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
return score;

