const today = new Date();
const day = today.getDay(); // 0=Sun
const offsetToSat = (6 - day + 7) % 7; // include today if Saturday
const weekendStart = new Date(today);
weekendStart.setDate(today.getDate() + offsetToSat);
const weekendEnd = new Date(weekendStart);
weekendEnd.setDate(weekendStart.getDate() + 1);
const weekendStartStr = dateOnly(weekendStart.toISOString());
const weekendEndStr = dateOnly(weekendEnd.toISOString());

function inWeekend(iso) {
  const dStr = dateOnly(iso);
  return dStr >= weekendStartStr && dStr <= weekendEndStr;
}

// Find qualifying indoor events for this weekend
const candidateEntries = [];
for (const activity of activities) {
  if (activity.activity_category !== 'indoor') continue;
  const acc = Array.isArray(activity.accessibility_features) ? activity.accessibility_features : [];
  if (!acc.includes('sensory_friendly') || !acc.includes('stroller_friendly')) continue;
  const rating = typeof activity.rating === 'number' ? activity.rating : 0;
  if (rating < 4.5) continue;

  const actSessions = sessionsByActivity[activity.id] || [];
  const weekendSessions = actSessions.filter(s => inWeekend(s.start_datetime));
  if (!weekendSessions.length) continue;

  // Not strictly needed for sorting by rating, but keep earliest weekend session for reference if desired
  let earliestSession = weekendSessions[0];
  for (const s of weekendSessions) {
    if (new Date(s.start_datetime) < new Date(earliestSession.start_datetime)) {
      earliestSession = s;
    }
  }

  const ratingCount = typeof activity.rating_count === 'number' ? activity.rating_count : 0;
  candidateEntries.push({ activity, session: earliestSession, rating, ratingCount });
}

candidateEntries.sort((a, b) => {
  if (b.rating !== a.rating) return b.rating - a.rating;
  return b.ratingCount - a.ratingCount;
});

const candidateActivityIds = candidateEntries.map(e => e.activity.id);
const top2 = candidateEntries.slice(0, 2);
const top2ActivityIds = top2.map(e => e.activity.id);

let favoritesList = null;
if (favoritesLists.length) {
  favoritesList = favoritesLists.find(l => l.name === 'Favorites') || favoritesLists[0];
}
let favoritedActivityIds = [];
if (favoritesList) {
  favoritedActivityIds = favoriteItems
    .filter(fi => fi.favorites_list_id === favoritesList.id)
    .map(fi => fi.activity_id);
}

const favoritedQualifyingIds = favoritedActivityIds.filter(id => candidateActivityIds.includes(id));
const top2FavoritedCount = top2ActivityIds.filter(id => favoritedActivityIds.includes(id)).length;

// CP1 (0.30): At least one qualifying indoor sensory- and stroller-friendly weekend event with rating ≥ 4.5 was favorited
checkpoints.push({ passed: favoritedQualifyingIds.length >= 1, weight: 0.30 });

// CP2 (0.30): At least two qualifying such events were favorited (or all, if fewer than 2 exist)
const requiredCount = Math.min(2, candidateActivityIds.length);
checkpoints.push({ passed: favoritedQualifyingIds.length >= requiredCount && requiredCount > 0, weight: 0.30 });

// CP3 (0.40): The two highest-rated qualifying events were both favorited
checkpoints.push({ passed: top2ActivityIds.length >= 2 && top2FavoritedCount === top2ActivityIds.length, weight: 0.40 });

const score = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
return score;
